                fontWeight: '700',
                letterSpacing: '0.04em',
              }}>
                {item.label}
              </span>
            </button>
          );
        })}
      </div>
    </div>
  );
}

/* src/components/MasteryGrid.tsx */
import { useState, useRef, useEffect } from 'react';
import { useMasteryStore } from '../store/masteryStore';
import VocabCard from './VocabCard';
import WordDetailDrawer from './WordDetailDrawer';
import { soundService } from '../services/soundService';
import { fetchSentenceSuggestions, fetchQuickTranslation, resolveApiKey, buildOfflineTranslation } from '../services/linaService';
import type { MasteryStatus, VocabWord } from '../types/mastery';

interface Props {
  onAskLina: (p: string) => void;
  onSaved?: (phraseId: string) => void;
  isSandboxMode: boolean;
  activeFilter: MasteryStatus | null;
  sortMode: string;
  sortDirection: 'asc' | 'desc';
  posFilter: string;
  setSortMode: (mode: any) => void;
  setSortDirection: (dir: any) => void;
  setPosFilter: (pos: string) => void;
}

const STATUS_RANK: Record<MasteryStatus, number> = {
  not_started: 0, introduced: 1, practicing: 2, confident: 3, mastered: 4
};

const MOVE_THRESHOLD = 8;

export default function MasteryGrid({
  onAskLina, onSaved, isSandboxMode, activeFilter, sortMode, sortDirection, posFilter,
  setSortMode, setSortDirection, setPosFilter
}: Props) {
  const { vocabulary, savePhrase } = useMasteryStore();
  // selectedWords is an ordered array — duplicates allowed so the same word
  // can appear multiple times in the sentence being built.
  const [selectedWords, setSelectedWords] = useState<string[]>([]);
  const [drawerId, setDrawerId] = useState<string | null>(null);
  const [magneticSuggestions, setMagneticSuggestions] = useState<string[]>([]);
  const [translation, setTranslation] = useState<string | null>(null);
  const [isAutoTranslating, setIsAutoTranslating] = useState(false);
  const [savedConfirm, setSavedConfirm] = useState(false);

  const longPressTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const confirmTimer  = useRef<ReturnType<typeof setTimeout> | null>(null);
  const isLongPress   = useRef(false);
  const pointerStart  = useRef<{ x: number; y: number } | null>(null);

  useEffect(() => {
    setTranslation(null);
    setIsAutoTranslating(false);
    if (confirmTimer.current) { clearTimeout(confirmTimer.current); confirmTimer.current = null; }
    setSavedConfirm(false);

    if (selectedWords.length === 0) { setMagneticSuggestions([]); return; }

    // Sandbox: build a word-by-word gloss immediately from local data — no API call.
    if (isSandboxMode) {
      setTranslation(buildOfflineTranslation(selectedWords, vocabulary));
      setMagneticSuggestions([]);
      return;
    }

    const apiKey = resolveApiKey();
    if (!apiKey) {
      setTranslation(buildOfflineTranslation(selectedWords, vocabulary));
      setMagneticSuggestions([]);
      return;
    }

    setIsAutoTranslating(true);
    let active = true;
    const timer = setTimeout(async () => {
      const uniqueWords = [...new Set(selectedWords)];
      const [transResult, suggResults] = await Promise.all([
        fetchQuickTranslation(apiKey, selectedWords.join(' ')),
        selectedWords.length >= 2
          ? fetchSentenceSuggestions(apiKey, uniqueWords)
          : Promise.resolve([]),
      ]);
      if (active) {
        setTranslation(transResult ?? buildOfflineTranslation(selectedWords, vocabulary));
        setMagneticSuggestions(suggResults);
        setIsAutoTranslating(false);
      }
    }, 900);

    return () => { active = false; clearTimeout(timer); setIsAutoTranslating(false); };
  }, [selectedWords, isSandboxMode]);

  // ── Pointer handlers ──────────────────────────────────────────────────────

  const cancelLongPress = () => {
    if (longPressTimer.current) { clearTimeout(longPressTimer.current); longPressTimer.current = null; }
    pointerStart.current = null;
  };

  const handlePointerDown = (e: React.PointerEvent, word: string) => {
    pointerStart.current = { x: e.clientX, y: e.clientY };
    isLongPress.current = false;
    longPressTimer.current = setTimeout(() => {
      isLongPress.current = true;
      soundService.playBlip(523.25, 'sine', 0.05);
      // Long-press always appends — duplicates are intentional.
      setSelectedWords(prev => [...prev, word]);
    }, 500);
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!pointerStart.current || !longPressTimer.current) return;
    const dx = e.clientX - pointerStart.current.x;
    const dy = e.clientY - pointerStart.current.y;
    if (Math.hypot(dx, dy) > MOVE_THRESHOLD) cancelLongPress();
  };

  const handlePointerUp = () => {
    pointerStart.current = null;
    if (longPressTimer.current) { clearTimeout(longPressTimer.current); longPressTimer.current = null; }
  };

  const handleCardClick = (word: VocabWord) => {
    if (isLongPress.current) { isLongPress.current = false; return; }
    if (selectedWords.length === 0) {
      setDrawerId(word.id);
    } else {
      // In multi-select mode, tapping always appends (allows "mi moku e moku").
      setSelectedWords(prev => [...prev, word.word]);
    }
  };

  // ── Builder actions ───────────────────────────────────────────────────────

  const handleSave = () => {
    const sentence = selectedWords.join(' ');
    savePhrase({ id: sentence, tp: sentence, en: translation ?? '', notes: '' });
    if (confirmTimer.current) clearTimeout(confirmTimer.current);
    setSavedConfirm(true);
    confirmTimer.current = setTimeout(() => {
      setSavedConfirm(false);
      confirmTimer.current = null;
      setSelectedWords([]);
      onSaved?.(sentence);
    }, 800);
  };

  // ── Display list ──────────────────────────────────────────────────────────

  const displayed = vocabulary
    .filter(w => !activeFilter || w.status === activeFilter)
    .filter(w => posFilter === 'All' || w.partOfSpeech.toLowerCase().includes(posFilter.toLowerCase()))
    .sort((a, b) => {
      if (sortMode === 'status') {
        const diff = STATUS_RANK[a.status] - STATUS_RANK[b.status];
        return sortDirection === 'asc' ? diff : -diff;
      }
      if (sortMode === 'length') {
        const diff = a.word.length - b.word.length;
        return sortDirection === 'asc' ? diff : -diff;
      }
      if (sortMode === 'partOfSpeech') {
        const diff = a.partOfSpeech.localeCompare(b.partOfSpeech);
        return sortDirection === 'asc' ? diff : -diff;
      }
      if (sortMode === 'useCount') {
        const diff = (a.useCount ?? 0) - (b.useCount ?? 0);
        return sortDirection === 'asc' ? diff : -diff;
      }
      const valA = a.word.toLowerCase();
      const valB = b.word.toLowerCase();
      return sortDirection === 'asc' ? valA.localeCompare(valB) : valB.localeCompare(valA);
    });

  return (
    <div
      className="mastery-grid-container"
      style={{ paddingBottom: selectedWords.length > 0 ? '240px' : undefined }}
      onClick={() => { if (selectedWords.length > 0) setSelectedWords([]); }}
    >
      <div className="grid-toolbar">
        <select value={sortMode} onChange={(e) => setSortMode(e.target.value)} className="sort-select">
          <option value="alphabetical">A → Z</option>
          <option value="status">Mastery Level</option>
          <option value="length">Word Length</option>
          <option value="partOfSpeech">Part of Speech</option>
          <option value="useCount">Most Used</option>
        </select>
        <button
          onClick={(e) => { e.stopPropagation(); setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc'); }}
          className="btn-toggle"
          style={{ flex: 'none', width: '42px' }}
        >
          {sortDirection === 'asc' ? '↑' : '↓'}
        </button>
      </div>

      <div className="mastery-grid__cards">
        {displayed.map((word) => {
          // Collect every position (1-indexed) where this word appears in the sentence.
          const positions: number[] = [];
          selectedWords.forEach((w, i) => { if (w === word.word) positions.push(i + 1); });
          const isSelected = positions.length > 0;

          return (
            <div
              key={word.id}
              onPointerDown={(e) => handlePointerDown(e, word.word)}
              onPointerMove={handlePointerMove}
              onPointerUp={handlePointerUp}
              onPointerCancel={cancelLongPress}
              onClick={(e) => { e.stopPropagation(); handleCardClick(word); }}
              className="grid-item-wrapper"
              style={{
                position: 'relative',
                opacity: selectedWords.length > 0 && !isSelected ? 0.3 : 1,
                touchAction: 'pan-y',
                cursor: 'pointer',
              }}
            >
              <VocabCard word={word} />

              {/* Position bubbles — one per occurrence in the sentence */}
              {positions.length > 0 && (
                <div style={{
                  position: 'absolute',
                  top: 3,
                  right: 3,
                  display: 'flex',
                  flexWrap: 'wrap',
                  gap: '2px',
                  justifyContent: 'flex-end',
                  maxWidth: '64px',
                  pointerEvents: 'none',
                }}>
                  {positions.map(pos => (
                    <span
                      key={pos}
                      style={{
                        background: '#3b82f6',
                        color: 'white',
                        borderRadius: '50%',
                        width: '16px',
                        height: '16px',
                        fontSize: '0.58rem',
                        fontWeight: 800,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        lineHeight: 1,
                        boxShadow: '0 1px 3px rgba(0,0,0,0.6)',
                      }}
                    >
                      {pos}
                    </span>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {selectedWords.length > 0 && (
        <div className="builder-panel" onClick={(e) => e.stopPropagation()}>
          <div className="builder-content">

            {/* Auto-translation — always visible, shows '...' while fetching */}
            <div style={{
              minHeight: '20px',
              color: isAutoTranslating ? '#444' : '#64748b',
              fontSize: '0.78rem',
              fontStyle: 'italic',
              marginBottom: '8px',
              letterSpacing: '0.01em',
            }}>
              {isAutoTranslating ? '· · ·' : (translation ?? '')}
            </div>

            {/* Sentence row: words + backspace (✕ removes last word) */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px', gap: '8px' }}>
              <div style={{ color: 'white', fontSize: '1.1rem', fontWeight: 'bold', flex: 1, wordBreak: 'break-word' }}>
                {selectedWords.join(' ')}
              </div>
              {/* ✕ = backspace: remove the last word */}
              <button
                onClick={() => setSelectedWords(prev => prev.slice(0, -1))}
                className="btn-toggle"
                style={{ flex: 'none', width: '34px', height: '34px', padding: 0, fontSize: '0.9rem' }}
                title="Remove last word"
              >⌫</button>
            </div>

            {/* AI sentence suggestions */}
            {magneticSuggestions.length > 0 && (
              <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap', marginBottom: '10px' }}>
                {magneticSuggestions.map((s, i) => (
                  <button
                    key={i}
                    className="suggestion-pill"
                    onClick={() => { onAskLina(`Let's practice this: "${s}"`); setSelectedWords([]); }}
                  >
                    {s}
                  </button>
                ))}
              </div>
            )}

            {/* Action row: ASK LINA | CLEAR | SAVE */}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '8px' }}>
              <button
                onClick={() => { onAskLina(`Let's work on: "${selectedWords.join(' ')}" — is this correct Toki Pona?`); setSelectedWords([]); }}
                className="btn-review"
                style={{ margin: 0, fontSize: '0.72rem', padding: '10px 4px' }}
              >
                ASK LINA
              </button>
              <button
                onClick={() => setSelectedWords([])}
                className="btn-review"
                style={{ margin: 0, fontSize: '0.72rem', padding: '10px 4px', background: '#374151' }}
              >
                CLEAR
              </button>
              <button
                onClick={handleSave}
                className="btn-review"
                style={{ margin: 0, fontSize: '0.72rem', padding: '10px 4px', background: savedConfirm ? '#10b981' : undefined }}
              >
                {savedConfirm ? 'SAVED ✓' : 'SAVE'}
              </button>
            </div>
          </div>
        </div>
      )}

      <WordDetailDrawer
        isOpen={!!drawerId}
        word={drawerId ? vocabulary.find(v => v.id === drawerId) ?? null : null}
        onClose={() => setDrawerId(null)}
        onAskLina={onAskLina}
        isSandboxMode={isSandboxMode}
      />
    </div>
  );
}

/* src/components/VocabCard.tsx */
import type { VocabWord, MasteryStatus } from '../types/mastery';

// Tier boundaries matching scoreToStatus() thresholds.
const TIER_RANGES: Record<MasteryStatus, [number, number]> = {
  not_started: [0,  19],
  introduced:  [20, 39],
  practicing:  [40, 64],
  confident:   [65, 84],
  mastered:    [85, 100],
};

const RING_COLOR: Record<MasteryStatus, string> = {
  not_started: '#374151',
  introduced:  '#1d4ed8',
  practicing:  '#92400e',
  confident:   '#16a34a',
  mastered:    '#22c55e',
};

// How far through the current tier the score is, as a 0–1 fraction.
function progressWithinTier(score: number, status: MasteryStatus): number {
  const [lo, hi] = TIER_RANGES[status];
  return Math.min(1, Math.max(0, (score - lo) / (hi - lo)));
}

export default function VocabCard({ word }: { word: VocabWord }) {
  const score  = word.confidenceScore ?? 0;
  const status = word.status;
  const color  = RING_COLOR[status];
  const fill   = progressWithinTier(score, status);

  // SVG ring geometry — sits flush with the card's border edge.
  // The ring radius equals half the card, minus half the stroke so it
  // doesn't overflow. We use a fixed viewport and let CSS size the element.
  const size   = 100;          // SVG viewport units
  const stroke = 3;
  const r      = (size - stroke) / 2;
  const circ   = 2 * Math.PI * r;
  const dash   = circ * fill;  // filled arc length
  const gap    = circ - dash;  // empty arc length

  return (
    <div
      className={`vocab-card vocab-card--${status}`}
      style={{ pointerEvents: 'none', position: 'relative' }}
    >
      {/* Confidence ring — absolutely positioned, border layer only */}
      <svg
        aria-hidden
        style={{
          position:  'absolute',
          inset:     -1,            // sits exactly on the 1px border edge
          width:     'calc(100% + 2px)',
          height:    'calc(100% + 2px)',
          borderRadius: '8px',
          overflow:  'visible',
          pointerEvents: 'none',
        }}
        viewBox={`0 0 ${size} ${size}`}
        preserveAspectRatio="none"
      >
        {/* Track (full ring, very faint) */}
        <rect
          x={stroke / 2} y={stroke / 2}
          width={size - stroke} height={size - stroke}
          rx={8} ry={8}
          fill="none"
          stroke={color}
          strokeWidth={stroke}
          strokeOpacity={0.15}
        />
        {/* Progress arc — uses a circle with dasharray so the fill sweeps
            around the perimeter. We rotate -90° so it starts at the top. */}
        <circle
          cx={size / 2} cy={size / 2} r={r}
          fill="none"
          stroke={color}
          strokeWidth={stroke}
          strokeOpacity={0.85}
          strokeLinecap="round"
          strokeDasharray={`${dash} ${gap}`}
          transform={`rotate(-90 ${size / 2} ${size / 2})`}
          style={{ transition: 'stroke-dasharray 0.4s ease' }}
        />
      </svg>

      <div className="vocab-card__word">{word.word}</div>
      <div className="vocab-card__pos">{word.partOfSpeech}</div>
    </div>
  );
}

import { motion, AnimatePresence } from 'framer-motion';
import { useMasteryStore } from '../store/masteryStore';
import { STATUS_META } from '../types/mastery';
import type { VocabWord, MasteryStatus } from '../types/mastery';

const TIER_RANGES: Record<MasteryStatus, [number, number]> = {
  not_started: [0,  19],
  introduced:  [20, 39],
  practicing:  [40, 64],
  confident:   [65, 84],
  mastered:    [85, 100],
};
const NEXT_STATUS: Partial<Record<MasteryStatus, MasteryStatus>> = {
  not_started: 'introduced',
  introduced:  'practicing',
  practicing:  'confident',
  confident:   'mastered',
};
const NEXT_THRESHOLD: Partial<Record<MasteryStatus, number>> = {
  not_started: 20, introduced: 40, practicing: 65, confident: 85,
};
const NEXT_COLOR: Record<MasteryStatus, string> = {
  not_started: '#1d4ed8',
  introduced:  '#92400e',
  practicing:  '#16a34a',
  confident:   '#22c55e',
  mastered:    '#22c55e',
};

function tierProgress(score: number, status: MasteryStatus): number {
  const [lo, hi] = TIER_RANGES[status];
  return Math.min(1, Math.max(0, (score - lo) / (hi - lo)));
}

export default function WordDetailDrawer({ isOpen, word, onClose, onAskLina, isSandboxMode }: { isOpen: boolean; word?: VocabWord | null; onClose: () => void; onAskLina: (p: string) => void; isSandboxMode: boolean }) {
  const partsOfSpeech = word?.partOfSpeech?.split('/').map(p => p.trim()) ?? [];
  const updateVocabStatus = useMasteryStore((s) => s.updateVocabStatus);

  return (
    <AnimatePresence>
      {isOpen && word && (
        <motion.div 
          key="backdrop" 
          className="drawer-backdrop" 
          initial={{ opacity: 0 }} 
          animate={{ opacity: 1 }} 
          exit={{ opacity: 0 }} 
          onClick={onClose} 
        />
      )}
      {isOpen && word && (
        <motion.div 
          key="drawer" 
          className="word-drawer" 
          initial={{ opacity: 0, scale: 0.95 }} 
          animate={{ opacity: 1, scale: 1 }} 
          exit={{ opacity: 0, scale: 0.95 }} 
          onClick={(e) => e.stopPropagation()}
          transition={{ type: 'spring', damping: 25, stiffness: 300 }}
        >
          <div className="drawer__handle" />
          <div className="drawer__scroll-area">
            <h2 style={{ fontSize: '2.4rem', marginBottom: '8px' }}>{word.word}</h2>
            <div
              onClick={() => isSandboxMode && updateVocabStatus(word.id, 'mastered')}
              style={{ cursor: 'pointer', color: '#888', marginBottom: '10px', fontSize: '0.8rem', fontWeight: 'bold' }}
            >
              {STATUS_META[word.status].emoji} {STATUS_META[word.status].label.toUpperCase()}
            </div>

            {/* Confidence progress bar — shows position within current tier */}
            {word.status !== 'mastered' && (
              <div style={{ marginBottom: '20px' }}>
                <div className="progress-bar-track">
                  <div
                    className="progress-bar-fill"
                    style={{
                      width: `${tierProgress(word.confidenceScore ?? 0, word.status) * 100}%`,
                      background: NEXT_COLOR[word.status],
                    }}
                  />
                </div>
                <div style={{ fontSize: '0.65rem', color: '#555', marginTop: '4px', fontWeight: 700 }}>
                  {Math.max(0, (NEXT_THRESHOLD[word.status] ?? 100) - (word.confidenceScore ?? 0))} pts to {STATUS_META[NEXT_STATUS[word.status]!].label}
                </div>
              </div>
            )}
            {word.status === 'mastered' && <div style={{ marginBottom: '20px' }} />}
            <div style={{ display: 'grid', gap: '12px' }}>
              {partsOfSpeech.map(pos => (
                <div key={pos} style={{ background: '#1a1a1a', padding: '16px', borderRadius: '12px', borderLeft: '4px solid #333' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <span style={{ fontWeight: 900, color: '#444', fontSize: '0.65rem' }}>{pos.toUpperCase()}</span>
                    <button onClick={() => { onAskLina(`toki Lina! Can we practice using "${word.word}" as a ${pos}?`); onClose(); }} style={{ background: 'transparent', border: 'none', color: '#3b82f6', fontWeight: 'bold', cursor: 'pointer' }}>ASK LINA</button>
                  </div>
                  <p style={{ marginTop: '8px', color: '#ccc', fontStyle: 'italic' }}>{word.meanings}</p>
                </div>
              ))}
            </div>
          </div>
          <div style={{ padding: '20px', borderTop: '1px solid #222' }}>
            <button onClick={onClose} style={{ width: '100%', padding: '12px', background: '#333', color: 'white', border: 'none', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer' }}>✕ CLOSE</button>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

/* src/services/linaService.ts */
import { GoogleGenerativeAI } from "@google/generative-ai";
import type { VocabWord, MasteryStatus } from '../types/mastery';

export const STATUS_EMOJI: Record<string, string> = {
  not_started: '⬜',
  introduced: '🔵',
  practicing: '🟡',
  confident: '🟢',
  mastered: '✅'
};

// Offline word-by-word gloss built from local vocabulary data — no API needed.
export function buildOfflineTranslation(selectedWords: string[], _vocabulary: VocabWord[]): string {
  return selectedWords.join(' · ');
}

export interface ProposedChange {
  type: 'vocab' | 'concept';
  id: string;
  newStatus: MasteryStatus;
}

// Resolves the API key with env-var fallback for local dev.
export function resolveApiKey(overrideKey?: string): string {
  return overrideKey
    || localStorage.getItem('TP_GEMINI_KEY')
    || (import.meta.env.VITE_GEMINI_API_KEY as string | undefined)
    || '';
}

export function buildSystemPrompt(
  vocabulary: any[],
  concepts: any[],
  studentName: string,
  activeCurriculumTitle?: string,
  activeModuleTitle?: string
) {
  const activeVocab = vocabulary
    .filter(v => v.status === 'introduced' || v.status === 'practicing' || v.status === 'confident')
    .map(v => `${v.word} (${v.status}) - Notes: ${v.sessionNotes || 'None'}`)
    .join('\n');

  const activeConcepts = concepts
    .filter(c => c.status === 'introduced' || c.status === 'practicing' || c.status === 'confident')
    .map(c => `${c.title} (${c.status}) - Notes: ${c.sessionNotes || 'None'}`)
    .join('\n');

  const lessonContext = activeModuleTitle
    ? `CURRENT LESSON GOAL:\nThe student has explicitly chosen to study: ${activeCurriculumTitle} - ${activeModuleTitle}. Focus your teaching and drills entirely on this topic today.`
    : `CURRENT LESSON GOAL:\nFree practice. Chat naturally and test them on their active vocabulary.`;

  return `
    You are an expert Toki Pona teacher.
    The student's name is ${studentName}.

    ${lessonContext}

    CURRENT STUDENT PROGRESS & MEMORY:
    You must use these session notes to remember what the student struggled with last time.
    Active Words:
    ${activeVocab || 'None'}

    Active Concepts:
    ${activeConcepts || 'None'}

    YOUR RULES:
    1. At the end of every response, if the student demonstrated knowledge, append a "PROPOSED CHANGES" section.

    FORMAT FOR PROPOSED CHANGES:
    ---
    CHANGE: vocab | [word_id] | [new_status]
    CHANGE: concept | [concept_id] | [new_status]
    ---
    Statuses: introduced, practicing, confident, mastered.
  `;
}

export async function* streamCompletion(
  apiKey: string,
  systemPrompt: string,
  history: { role: 'user' | 'assistant'; content: string }[]
) {
  const genAI = new GoogleGenerativeAI(apiKey);
  const model = genAI.getGenerativeModel({ model: "gemini-2.5-flash", systemInstruction: systemPrompt });

  const chat = model.startChat({
    history: history.slice(0, -1).map(h => ({
      role: h.role === 'user' ? 'user' : 'model',
      parts: [{ text: h.content }],
    }))
  });

  const lastMessage = history[history.length - 1].content;
  const result = await chat.sendMessageStream(lastMessage);
  for await (const chunk of result.stream) yield chunk.text();
}

// Strips markdown code fences before JSON.parse.
function sanitizeJson(text: string): string {
  return text.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '').trim();
}

export async function fetchSentenceSuggestions(apiKey: string, words: string[]) {
  const genAI = new GoogleGenerativeAI(apiKey);
  const model = genAI.getGenerativeModel({
    model: "gemini-2.5-flash",
    generationConfig: { responseMimeType: "application/json" },
  });
  const prompt = `Act as a Toki Pona tutor. Given these words: [${words.join(', ')}], generate 3 short grammatically correct Toki Pona sentences using most or all of them. You MAY add particles like "li", "e", "en", "la", or "pi". Return a JSON array of strings: ["sentence 1", "sentence 2", "sentence 3"]`;
  try {
    const result = await model.generateContent(prompt);
    return JSON.parse(sanitizeJson(result.response.text())) as string[];
  } catch (e) {
    console.error('Lina Suggestion Error:', e);
    return [];
  }
}

export async function fetchQuickTranslation(apiKey: string, text: string) {
  const genAI = new GoogleGenerativeAI(apiKey);
  const model = genAI.getGenerativeModel({ model: "gemini-2.5-flash" });
  const prompt = `Translate this Toki Pona phrase to English: "${text}". Provide ONLY the direct English translation, no other text, quotes, or explanation.`;
  try {
    const result = await model.generateContent(prompt);
    return result.response.text().trim();
  } catch (e) {
    console.error('Lina Translation Error:', e);
    return null;
  }
}

export async function fetchExamplesForWord(apiKey: string, word: string, partsOfSpeech: string[]) {
  const genAI = new GoogleGenerativeAI(apiKey);
  const model = genAI.getGenerativeModel({
    model: "gemini-2.5-flash",
    generationConfig: { responseMimeType: "application/json" },
  });
  const prompt = `Act as a Toki Pona dictionary. For the word "${word}", provide one simple example sentence for each of these parts of speech: ${partsOfSpeech.join(', ')}. Return ONLY a JSON object mapping each part of speech to a sentence, e.g. {"noun": "sentence", "verb": "sentence"}`;
  try {
    const result = await model.generateContent(prompt);
    return JSON.parse(sanitizeJson(result.response.text())) as Record<string, string>;
  } catch (e) {
    console.error('Lina Dictionary Error:', e);
    return partsOfSpeech.reduce((acc, pos) => ({ ...acc, [pos]: `${word} li lon.` }), {} as Record<string, string>);
  }
}

export function stripProposedChanges(text: string) {
  return text.split('---')[0].trim();
}

// Parses "CHANGE: vocab | word_id | new_status" and "CHANGE: concept | id | new_status"
export function parseProposedChanges(text: string): ProposedChange[] | null {
  const VALID_STATUSES: MasteryStatus[] = ['not_started', 'introduced', 'practicing', 'confident', 'mastered'];
  const changes: ProposedChange[] = [];
  for (const rawLine of text.split('\n')) {
    const line = rawLine.replace(/\*\*/g, '').replace(/\s+/g, ' ').trim();
    if (!/change:\s*(vocab|concept)/i.test(line)) continue;
    const parts = line.split('|').map(p => p.trim());
    if (parts.length < 3) continue;
    const typeMatch = parts[0].match(/change:\s*(vocab|concept)/i);
    if (!typeMatch) continue;
    const type = typeMatch[1].toLowerCase() as 'vocab' | 'concept';
    const id = parts[1];
    const rawStatus = parts[2].toLowerCase().replace(/[^a-z_]/g, '') as MasteryStatus;
    if (id && VALID_STATUSES.includes(rawStatus)) {
      changes.push({ type, id, newStatus: rawStatus });
    }
  }
  return changes.length > 0 ? changes : null;
}

export async function fetchSessionRecap(
  apiKey: string,
  changes: ProposedChange[]
): Promise<string> {
  const genAI = new GoogleGenerativeAI(apiKey);
  const model = genAI.getGenerativeModel({ model: "gemini-2.5-flash" });
  const summary = changes
    .map(c => `${c.id}: → ${c.newStatus}`)
    .join(', ');
  const prompt = `You are a Toki Pona teacher giving a student a brief end-of-session summary. The following words and concepts had their mastery status updated this session: ${summary}. Write 2–3 sentences in plain English (no bullet points, no headers) describing what improved. Keep it concise and encouraging.`;
  try {
    const result = await model.generateContent(prompt);
    return result.response.text().trim();
  } catch (e) {
    console.error('Session recap error:', e);
    const improved = changes.filter(c => c.newStatus !== 'not_started').map(c => c.id);
    return improved.length
      ? `Session complete! Great work on: ${improved.join(', ')}.`
      : 'Session complete! Keep practising.';
  }
}

