// src/types/mastery.ts
// ─── Status ──────────────────────────────────────────────────────────────────

export const MASTERY_STATUS = {
  NOT_STARTED: 'not_started',
  INTRODUCED: 'introduced',
  PRACTICING: 'practicing',
  CONFIDENT: 'confident',
  MASTERED: 'mastered',
} as const;

export type MasteryStatus = (typeof MASTERY_STATUS)[keyof typeof MASTERY_STATUS];

export const STATUS_META: Record<
  MasteryStatus,
  { emoji: string; label: string; meaning: string }
> = {
  not_started: {
    emoji: '⬜',
    label: 'Not Started',
    meaning: 'Concept has not yet been introduced.',
  },
  introduced: {
    emoji: '🔵',
    label: 'Introduced',
    meaning: 'Concept has been presented but not yet practiced or tested.',
  },
  practicing: {
    emoji: '🟡',
    label: 'Practicing',
    meaning: 'Actively working on it; some errors or hesitation still present.',
  },
  confident: {
    emoji: '🟢',
    label: 'Confident',
    meaning: 'Consistently correct with some conscious effort.',
  },
  mastered: {
    emoji: '✅',
    label: 'Mastered',
    meaning:
      'Fully automatic — confirmed correct across multiple sessions. Set by mutual agreement.',
  },
};

// ─── Score → Status derivation ────────────────────────────────────────────────
// Status is derived from confidenceScore; it is never stored independently.
//   0–19  → not_started
//  20–39  → introduced
//  40–64  → practicing
//  65–84  → confident
//  85–100 → mastered

export function scoreToStatus(score: number): MasteryStatus {
  if (score >= 85) return 'mastered';
  if (score >= 65) return 'confident';
  if (score >= 40) return 'practicing';
  if (score >= 20) return 'introduced';
  return 'not_started';
}

// Midpoint of each tier's range — used to seed confidenceScore when reading
// legacy cloud data that only has a status field.
export const STATUS_MIDPOINT: Record<MasteryStatus, number> = {
  not_started: 9,
  introduced:  29,
  practicing:  52,
  confident:   74,
  mastered:    92,
};

// ─── Grammar Concepts ─────────────────────────────────────────────────────────

export interface GrammarConcept {
  id: string;
  concept: string;
  status: MasteryStatus;
  sessionNotes: string;
}

// ─── Chapters ─────────────────────────────────────────────────────────────────

export interface Chapter {
  id: string;
  title: string;
  order: number;
  // order === 0 is reserved for the Introduction section
  concepts: GrammarConcept[];
}

// ─── Vocabulary ───────────────────────────────────────────────────────────────

export interface VocabWord {
  id: string;
  word: string;
  partOfSpeech: string;
  meanings: string;
  // confidenceScore is the source of truth (0–100).
  // status is derived from it via scoreToStatus() and kept in sync.
  confidenceScore: number;
  status: MasteryStatus;
  useCount: number;
  isMasteryCandidate: boolean;
  sessionNotes: string;
}

// ─── Top-level Map ────────────────────────────────────────────────────────────

export interface SavedPhrase {
  id: string;
  tp: string;
  en: string;
  notes: string;
}

export interface MasteryMap {
  studentName: string;
  profileImage: string;
  curriculumLevel: string;
  lastUpdated: string;
  chapters: Chapter[];   // index 0 = Introduction
  vocabulary: VocabWord[];

  // NEW FEATURES
  savedPhrases: (string | SavedPhrase)[];
  currentStreak: number;
  lastActiveDate: string;
}


// ─── Status summary helper type ───────────────────────────────────────────────

export type StatusSummary = Record<MasteryStatus, number>;

/* src/components/Dashboard.tsx */
import { useState } from 'react';
import { useMasteryStore } from '../store/masteryStore';
import ProgressSummary from './ProgressSummary';
import MasteryGrid from './MasteryGrid';
import PhraseGrid from './PhraseGrid';
import SettingsDrawer from './SettingsDrawer';
import UserProfileDrawer from './UserProfileDrawer';
import SetupScreen from './SetupScreen';
import type { MasteryStatus } from '../types/mastery';

export default function Dashboard({ onStartSession, onAskLina, isSandboxMode, setIsSandboxMode }: {
  onStartSession: () => void;
  onAskLina: (p: string) => void;
  isSandboxMode: boolean;
  setIsSandboxMode: (val: boolean) => void;
}) {
  const { studentName, currentStreak, vocabulary, savedPhrases } = useMasteryStore();
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);

  const [activeFilter, setActiveFilter] = useState<MasteryStatus | null>(null);
  const [viewMode, setViewMode] = useState<'grid' | 'phrasebook'>('grid');
  const [posFilter, setPosFilter] = useState('All');
  const [sortMode, setSortMode] = useState<string>('alphabetical');
  const [sortDirection, setSortDirection] = useState<'asc' | 'desc'>('asc');
  const [focusPhraseId, setFocusPhraseId] = useState<string | null>(null);

  if (!studentName || studentName === 'Student') return <SetupScreen />;

  const handleDailyReview = () => {
    const practicingWords = vocabulary
      .filter(w => w.status === 'practicing')
      .sort((a, b) => a.confidenceScore - b.confidenceScore) // lowest scores first
      .slice(0, 6)
      .map(w => `${w.word} (score: ${w.confidenceScore})`);
    const introducedWords = vocabulary
      .filter(w => w.status === 'introduced')
      .slice(0, 4)
      .map(w => w.word);

    if (practicingWords.length === 0 && introducedWords.length === 0) {
      onAskLina(`toki Lina! I have no words to review right now — either I haven't started yet or everything is mastered. What should we work on?`);
      return;
    }

    const parts: string[] = [];
    if (practicingWords.length > 0) parts.push(`Practicing (lowest scores first): ${practicingWords.join(', ')}`);
    if (introducedWords.length > 0) parts.push(`Introduced (need more practice): ${introducedWords.join(', ')}`);

    onAskLina(`toki Lina! Let's do a daily review. Please follow the 3-phase lesson structure.\n\n${parts.join('\n')}\n\nStart with Phase 1 — warm up my practicing words.`);
  };

  // Called by MasteryGrid after saving a phrase — switch to phrasebook and open note editor.
  const handleSaved = (phraseId: string) => {
    setFocusPhraseId(phraseId);
    setViewMode('phrasebook');
  };

  return (
    <div className="dashboard">
      <header className="dashboard__header">
        <div className="dashboard__header-left">
          <h1 className="dashboard__title">TOKI PONA</h1>
          <button onClick={() => setIsProfileOpen(true)} className="dashboard__profile-trigger">👤 {studentName.toUpperCase()}</button>
        </div>
        <div className="dashboard__header-right">
          {currentStreak > 0 && <div className="dashboard__streak">🔥 {currentStreak}</div>}
          <button onClick={onStartSession} className="dashboard__icon-btn">💬</button>
          <button onClick={() => setIsSettingsOpen(true)} className="dashboard__icon-btn">⚙️</button>
        </div>
      </header>

      <main className="dashboard__main">
        <ProgressSummary activeFilter={activeFilter} onFilterClick={setActiveFilter} />
        <button onClick={handleDailyReview} className="btn-review">⚡ START DAILY REVIEW</button>

        <div className="dashboard__view-toggle">
          <button onClick={() => setViewMode('grid')} className={`btn-toggle ${viewMode === 'grid' ? 'active' : ''}`}>VOCAB GRID</button>
          <button onClick={() => setViewMode('phrasebook')} className={`btn-toggle ${viewMode === 'phrasebook' ? 'active' : ''}`}>PHRASEBOOK</button>
        </div>

        {viewMode === 'grid' ? (
          <>
            <div className="grid-toolbar">
              <select
                id="pos-filter"
                value={posFilter}
                onChange={(e) => setPosFilter(e.target.value)}
                className="sort-select"
              >
                <option value="All">All Parts of Speech</option>
                <option value="noun">Noun</option>
                <option value="verb">Verb</option>
                <option value="adjective">Adjective</option>
                <option value="adverb">Adverb</option>
                <option value="number">Number</option>
                <option value="phrase">Phrase</option>
              </select>
            </div>

            <MasteryGrid
              onAskLina={onAskLina}
              onSaved={handleSaved}
              isSandboxMode={isSandboxMode}
              activeFilter={activeFilter}
              sortMode={sortMode}
              sortDirection={sortDirection}
              posFilter={posFilter}
              setSortMode={setSortMode}
              setSortDirection={setSortDirection}
              setPosFilter={setPosFilter}
            />
          </>
        ) : (
          <div style={{ padding: '20px 0' }}>
            <PhraseGrid
              onAskLina={onAskLina}
              activeFilter={activeFilter}
              selectedWords={[]}
              focusPhraseId={focusPhraseId}
              clearFocusPhrase={() => setFocusPhraseId(null)}
            />

            <h3 style={{ marginTop: '30px', marginBottom: '15px', color: '#fff', fontSize: '1.2rem', fontWeight: 'bold', borderBottom: '1px solid #333', paddingBottom: '10px' }}>
              SAVED PHRASES
            </h3>
            {savedPhrases.length === 0 ? <p style={{ color: '#888' }}>No phrases saved yet.</p> : savedPhrases.map((p, i) => (
              <div key={i} style={{ background: '#111', borderLeft: '4px solid #10b981', padding: '15px', borderRadius: '8px', marginBottom: '10px', color: '#eee' }}>
                {typeof p === 'string' ? p : p.tp}
              </div>
            ))}
          </div>
        )}
      </main>

      <SettingsDrawer isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} isSandboxMode={isSandboxMode} setIsSandboxMode={setIsSandboxMode} />
      <UserProfileDrawer isOpen={isProfileOpen} onClose={() => setIsProfileOpen(false)} />
    </div>
  );
}

/* src/components/PhraseGrid.tsx */
import { useState, useEffect } from 'react';
import { useMasteryStore } from '../store/masteryStore';
import type { MasteryStatus } from '../types/mastery';

interface Props {
  onAskLina: (prompt: string) => void;
  activeFilter: MasteryStatus | null;
  selectedWords: string[];
  focusPhraseId?: string | null;
  clearFocusPhrase?: () => void;
}

const PHRASES = [
  { tp: "ale li pona.", en: "Everything is good." },
  { tp: "ni li lili.", en: "That is small." },
  { tp: "sina wawa.", en: "You are strong." },
  { tp: "pali pona!", en: "Good work!" },
  { tp: "mi pilin ike.", en: "I feel bad." },
  { tp: "sina sona mute.", en: "You are smart." },
  { tp: "sina pona tawa jan.", en: "You are kind." }
];

export default function PhraseGrid({ onAskLina, activeFilter, selectedWords, focusPhraseId, clearFocusPhrase }: Props) {
  const { vocabulary, savedPhrases, updatePhraseNote, deletePhrase } = useMasteryStore();
  const [editingId, setEditingId] = useState<string | null>(null);
  const [noteInput, setNoteInput] = useState('');

  const clean = (w: string) => w.toLowerCase().replace(/[.!?,]/g, '');

  const safeSavedPhrases = savedPhrases || [];

  useEffect(() => {
    if (focusPhraseId) {
      setEditingId(focusPhraseId);
      const target = safeSavedPhrases.find(p => typeof p !== 'string' && p.id === focusPhraseId);
      setNoteInput(target && typeof target !== 'string' ? target.notes : '');
    }
  }, [focusPhraseId, safeSavedPhrases]);

  const normalizedSaved = safeSavedPhrases.map(p => 
    typeof p === 'string' ? { id: p, tp: p, en: 'User Saved Phrase *', notes: '' } : p
  );

  const combined = [
    ...PHRASES.map(p => ({ ...p, isSaved: false, id: p.tp, notes: '' })), 
    ...normalizedSaved.map(p => ({ ...p, isSaved: true }))
  ];

  const filtered = combined.filter(p => {
    if (!p.isSaved) {
      const ws = p.tp.split(' ').map(clean);
      const isKnown = ws.every(w => {
        const v = vocabulary.find(i => i.word === w);
        return v && v.status !== 'not_started';
      });
      if (!isKnown) return false;
    }

    if (selectedWords.length > 0) {
      const ws = p.tp.split(' ').map(clean);
      if (!selectedWords.every(sw => ws.includes(clean(sw)))) return false;
    }

    if (activeFilter && !p.isSaved) {
      const ws = p.tp.split(' ').map(clean);
      if (!ws.some(w => vocabulary.find(i => i.word === w)?.status === activeFilter)) return false;
    }

    return true;
  });

  return (
    <section className="phrase-grid">
      <h2 className="section-title" style={{ marginBottom: '20px' }}>
        {selectedWords.length > 0 ? `SUGGESTED COMBINATIONS` : 'PRACTICE PHRASES'}
      </h2>
      <div style={{ display: 'grid', gap: '12px', gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))' }}>
        {filtered.map((p) => (
          <div key={p.id} style={{ background: p.isSaved ? '#0f172a' : '#111', padding: '16px', borderRadius: '8px', border: p.isSaved ? '1px solid #3b82f6' : '1px solid #333' }}>
            <div onClick={() => onAskLina(`Let's practice: "${p.tp}"`)} style={{ cursor: 'pointer' }}>
              <div style={{ fontWeight: 'bold', fontSize: '1.05rem', color: p.isSaved ? '#60a5fa' : '#fff' }}>{p.tp} {p.isSaved && '*'}</div>
              <div style={{ fontSize: '0.8rem', color: p.isSaved ? '#94a3b8' : '#777', fontStyle: 'italic' }}>{p.en}</div>
            </div>
            {p.isSaved && (
              <div style={{ marginTop: '10px', paddingTop: '10px', borderTop: '1px solid #1e293b' }}>
                {p.notes && <div style={{ fontSize: '0.8rem', color: '#cbd5e1', marginBottom: '8px', padding: '6px', background: '#1e293b', borderRadius: '4px' }}>📝 {p.notes}</div>}
                <div style={{ display: 'flex', gap: '8px' }}>
                  <button onClick={() => { setEditingId(p.id); setNoteInput(p.notes); }} className="btn-toggle" style={{ padding: '4px 8px', fontSize: '0.65rem', width: 'auto' }}>
                    {p.notes ? 'EDIT NOTE' : '+ NOTE'}
                  </button>
                  <button onClick={() => { if(window.confirm('Delete this saved phrase?')) deletePhrase(p.id); }} className="btn-toggle" style={{ padding: '4px 8px', fontSize: '0.65rem', width: 'auto', background: '#7f1d1d' }}>
                    DELETE
                  </button>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>

      {editingId && (
        <div className="drawer-backdrop" onClick={() => { setEditingId(null); clearFocusPhrase?.(); }} style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 5000 }}>
          <div onClick={e => e.stopPropagation()} style={{ background: '#111', padding: '20px', borderRadius: '12px', width: '90%', maxWidth: '400px', border: '1px solid #444', boxShadow: '0 10px 30px rgba(0,0,0,0.8)' }}>
            <h3 style={{ color: '#fff', marginBottom: '15px', marginTop: 0 }}>Phrase Note</h3>
            <textarea value={noteInput} onChange={e => setNoteInput(e.target.value)} placeholder="Add context to this phrase..." style={{ width: '100%', height: '100px', background: '#222', color: '#fff', border: '1px solid #444', borderRadius: '8px', padding: '10px', marginBottom: '15px', resize: 'none', outline: 'none' }} autoFocus />
            <div style={{ display: 'flex', gap: '10px' }}>
              <button onClick={() => { updatePhraseNote(editingId, noteInput); setEditingId(null); clearFocusPhrase?.(); }} className="btn-review" style={{ margin: 0, flex: 2 }}>SAVE</button>
              <button onClick={() => { setEditingId(null); clearFocusPhrase?.(); }} className="btn-toggle" style={{ flex: 1 }}>CANCEL</button>
            </div>
          </div>
        </div>
      )}
    </section>
  );
}

// One-shot transformation: resets initialMasteryMap.ts to a clean fresh-slate
// state suitable for any new user.
//
// Run with:  node scripts/reset-to-fresh-slate.cjs

const fs = require('fs');
const path = require('path');

const filePath = path.resolve(__dirname, '../src/data/initialMasteryMap.ts');
let src = fs.readFileSync(filePath, 'utf8');

// ── 1. Reset every non-not_started status ─────────────────────────────────
src = src.replace(/status: 'introduced'/g,  "status: 'not_started'");
src = src.replace(/status: 'practicing'/g,  "status: 'not_started'");
src = src.replace(/status: 'confident'/g,   "status: 'not_started'");
src = src.replace(/status: 'mastered'/g,    "status: 'not_started'");

// ── 2. Clear mastery-candidate flags ─────────────────────────────────────
src = src.replace(/isMasteryCandidate: true/g, 'isMasteryCandidate: false');

// ── 3. Clear session notes — handles both quote styles and both layouts:
//      multiline (key on one line, value indented on next) and
//      single-line (key and value on the same line).
src = src.replace(/sessionNotes:\s*\n\s*'[^']*'/g, "sessionNotes: ''");
src = src.replace(/sessionNotes:\s*\n\s*"[^"]*"/g, "sessionNotes: ''");
src = src.replace(/sessionNotes: '[^']+'/g,         "sessionNotes: ''");
src = src.replace(/sessionNotes: "[^"]+"/g,         "sessionNotes: ''");

// ── 4. Anonymise top-level metadata ──────────────────────────────────────
src = src.replace(/studentName:\s*'[^']*'/, "studentName: ''");
src = src.replace(/lastUpdated:\s*'[^']*'/,  "lastUpdated: ''");

// ── 5. Update the sync comment in the file header ────────────────────────
src = src.replace(
  /\/\/ Last synced:.*\n/,
  '// Fresh-slate default — all statuses start at Not Started.\n'
);

fs.writeFileSync(filePath, src, 'utf8');
console.log('Done. initialMasteryMap.ts has been reset to a fresh slate.');

